INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ras e na vertente económica do setor dos portos comerciais e transportes marítimos, bem como a gestão de contratos de concessão em que o Estado seja concedente nos referidos setores ou em outros setores, nomeadamente relativos a transporte aéreo e infraestruturas aeroportuárias, de modo a satisfazer as necessidades de mobilidade de pessoas e bens. 
